// monster-sweep-recon — sovereign generalized-cylinder (SWEEP) reconstruction.
//
// A banana (or any sweep-like object: bottle, limb, tool) is a curved tube.
// This reconstructs it from REAL PHOTOS on a black background, NOT parametrically:
//
//   1. Segment the best PROFILE image (black bg -> luma threshold).
//   2. PCA-align the silhouette so its long axis is +X.
//   3. Per slice along X: centerline_y(x) = midpoint of the silhouette top/bottom
//      (captures the CURVE); halfWidth(x) = (bottom-top)/2 (captures the TAPER).
//   4. Extract a CROSS-SECTION profile from an END-ON image (the teardrop), or
//      fall back to a rounded slightly-flattened cross-section. Depth (unseen in
//      profile) = halfWidth * depth_ratio (bananas are a bit flatter than round).
//   5. SWEEP the cross-section ring along the centerline, scaled by halfWidth(x),
//      capped at both tapered ends -> a clean closed banana surface.
//   6. COLOR each surface vertex by sampling the profile image's real pixels
//      at the vertex's (x, centerline) projected position -> real yellow + speckles.
//   7. Emit a faced PLY (x y z nx ny nz red green blue + triangle faces),
//      long axis on X, centered, length normalized to ~2 units.
//
// All silhouette/curve/width/cross-section/color come from the actual images.

use image::{GenericImageView, Rgb};
use std::fs::File;
use std::io::{BufWriter, Write};
use std::path::PathBuf;

#[derive(Clone)]
struct Mask {
    w: usize,
    h: usize,
    fg: Vec<bool>,
    // original RGB for color sampling (row-major, 3 bytes/px)
    rgb: Vec<u8>,
}

fn load_mask(path: &PathBuf, thresh: f32, max_dim: u32) -> Mask {
    let img = image::open(path).unwrap_or_else(|e| panic!("open {:?}: {}", path, e));
    let img = img.resize(max_dim, max_dim, image::imageops::FilterType::Lanczos3);
    let (w, h) = img.dimensions();
    let (w, h) = (w as usize, h as usize);
    let mut fg = vec![false; w * h];
    let mut rgb = vec![0u8; w * h * 3];
    for y in 0..h {
        for x in 0..w {
            let p = img.get_pixel(x as u32, y as u32);
            let (r, g, b) = (p[0] as f32, p[1] as f32, p[2] as f32);
            let luma = (0.2126 * r + 0.7152 * g + 0.0722 * b) / 255.0;
            let i = y * w + x;
            fg[i] = luma > thresh;
            rgb[i * 3] = p[0];
            rgb[i * 3 + 1] = p[1];
            rgb[i * 3 + 2] = p[2];
        }
    }
    // keep only the largest connected component (drops the corner sparkle/logo)
    keep_largest_component(&mut fg, w, h);
    // Specular inpaint: the shiny sheen is a bright, chroma-washed blob on the
    // skin. Flag those pixels and replace each with the average of its nearby
    // NON-specular skin neighbors, so no glaring highlight is ever sampled.
    inpaint_specular(&mut rgb, &fg, w, h);
    Mask { w, h, fg, rgb }
}

// Detect specular skin pixels (bright + low chroma) and diffuse non-specular
// neighbor color into them with a few Jacobi passes. Diffuse-only -> the ripe
// yellow flows over the sheen without touching brown speckles.
fn inpaint_specular(rgb: &mut [u8], fg: &[bool], w: usize, h: usize) {
    let mut spec = vec![false; w * h];
    let mut any = false;
    for i in 0..w * h {
        if !fg[i] {
            continue;
        }
        let (r, g, b) = (
            rgb[i * 3] as f32 / 255.0,
            rgb[i * 3 + 1] as f32 / 255.0,
            rgb[i * 3 + 2] as f32 / 255.0,
        );
        let mx = r.max(g).max(b);
        let mn = r.min(g).min(b);
        let s = if mx <= 1e-5 { 0.0 } else { (mx - mn) / mx };
        if (mx > 0.74 && s < 0.46) || mx > 0.90 {
            spec[i] = true;
            any = true;
        }
    }
    if !any {
        return;
    }
    // iteratively fill specular pixels from non-specular skin neighbors
    for _ in 0..40 {
        let src = rgb.to_vec();
        let prev = spec.clone();
        for y in 0..h {
            for x in 0..w {
                let i = y * w + x;
                if !spec[i] || !fg[i] {
                    continue;
                }
                let mut acc = [0u32; 3];
                let mut cnt = 0u32;
                let nb = |nx: usize, ny: usize, acc: &mut [u32; 3], cnt: &mut u32| {
                    let j = ny * w + nx;
                    if fg[j] && !prev[j] {
                        acc[0] += src[j * 3] as u32;
                        acc[1] += src[j * 3 + 1] as u32;
                        acc[2] += src[j * 3 + 2] as u32;
                        *cnt += 1;
                    }
                };
                if x > 0 {
                    nb(x - 1, y, &mut acc, &mut cnt);
                }
                if x + 1 < w {
                    nb(x + 1, y, &mut acc, &mut cnt);
                }
                if y > 0 {
                    nb(x, y - 1, &mut acc, &mut cnt);
                }
                if y + 1 < h {
                    nb(x, y + 1, &mut acc, &mut cnt);
                }
                if cnt > 0 {
                    rgb[i * 3] = (acc[0] / cnt) as u8;
                    rgb[i * 3 + 1] = (acc[1] / cnt) as u8;
                    rgb[i * 3 + 2] = (acc[2] / cnt) as u8;
                    spec[i] = false; // now filled; acts as source next pass
                }
            }
        }
    }
    // any still-flagged interior pixels: clamp brightness toward a ripe yellow
    for i in 0..w * h {
        if spec[i] {
            rgb[i * 3] = 200;
            rgb[i * 3 + 1] = 170;
            rgb[i * 3 + 2] = 40;
        }
    }
}

fn keep_largest_component(fg: &mut [bool], w: usize, h: usize) {
    let mut label = vec![0u32; w * h];
    let mut next = 0u32;
    let mut best_label = 0u32;
    let mut best_count = 0usize;
    let mut stack: Vec<usize> = Vec::new();
    for start in 0..w * h {
        if !fg[start] || label[start] != 0 {
            continue;
        }
        next += 1;
        let mut count = 0usize;
        stack.push(start);
        label[start] = next;
        while let Some(p) = stack.pop() {
            count += 1;
            let (x, y) = (p % w, p / w);
            let push = |nx: usize, ny: usize, st: &mut Vec<usize>, lb: &mut Vec<u32>| {
                let q = ny * w + nx;
                if fg[q] && lb[q] == 0 {
                    lb[q] = next;
                    st.push(q);
                }
            };
            if x > 0 {
                push(x - 1, y, &mut stack, &mut label);
            }
            if x + 1 < w {
                push(x + 1, y, &mut stack, &mut label);
            }
            if y > 0 {
                push(x, y - 1, &mut stack, &mut label);
            }
            if y + 1 < h {
                push(x, y + 1, &mut stack, &mut label);
            }
        }
        if count > best_count {
            best_count = count;
            best_label = next;
        }
    }
    for i in 0..w * h {
        if label[i] != best_label {
            fg[i] = false;
        }
    }
}

// PCA of the foreground -> centroid + orthonormal axes (major, minor) in pixel space.
struct Pca {
    cx: f32,
    cy: f32,
    // unit major axis (long), unit minor axis
    ux: f32,
    uy: f32,
    vx: f32,
    vy: f32,
}

fn pca(m: &Mask) -> Pca {
    let (mut sx, mut sy, mut n) = (0f64, 0f64, 0f64);
    for y in 0..m.h {
        for x in 0..m.w {
            if m.fg[y * m.w + x] {
                sx += x as f64;
                sy += y as f64;
                n += 1.0;
            }
        }
    }
    let cx = (sx / n) as f32;
    let cy = (sy / n) as f32;
    let (mut sxx, mut syy, mut sxy) = (0f64, 0f64, 0f64);
    for y in 0..m.h {
        for x in 0..m.w {
            if m.fg[y * m.w + x] {
                let dx = x as f64 - cx as f64;
                let dy = y as f64 - cy as f64;
                sxx += dx * dx;
                syy += dy * dy;
                sxy += dx * dy;
            }
        }
    }
    sxx /= n;
    syy /= n;
    sxy /= n;
    // eigenvector of the 2x2 covariance for the larger eigenvalue = major axis.
    let tr = sxx + syy;
    let det = sxx * syy - sxy * sxy;
    let disc = ((tr * tr) / 4.0 - det).max(0.0).sqrt();
    let l1 = tr / 2.0 + disc; // larger eigenvalue
                              // (sxx - l1) ux + sxy uy = 0  ->  major dir ~ (sxy, l1 - sxx)
    let (mut ux, mut uy) = (sxy, l1 - sxx);
    let nrm = (ux * ux + uy * uy).sqrt();
    if nrm < 1e-9 {
        ux = 1.0;
        uy = 0.0;
    } else {
        ux /= nrm;
        uy /= nrm;
    }
    Pca {
        cx,
        cy,
        ux: ux as f32,
        uy: uy as f32,
        vx: -uy as f32,
        vy: ux as f32,
    }
}

// Centerline + width profile sampled along the major axis.
struct Profile {
    // for each of `n` slices: axial position u (centered, px), centerline offset
    // along minor axis t (px), and half-width along minor axis (px).
    u: Vec<f32>,
    t: Vec<f32>,
    half: Vec<f32>,
    umin: f32,
    umax: f32,
}

fn extract_profile(m: &Mask, p: &Pca, n_slices: usize) -> Profile {
    // Project every fg pixel into axis-aligned (u along major, t along minor).
    // Bin by u; in each bin record min/max t -> centerline & halfwidth.
    let mut umin = f32::INFINITY;
    let mut umax = f32::NEG_INFINITY;
    for y in 0..m.h {
        for x in 0..m.w {
            if m.fg[y * m.w + x] {
                let dx = x as f32 - p.cx;
                let dy = y as f32 - p.cy;
                let u = dx * p.ux + dy * p.uy;
                umin = umin.min(u);
                umax = umax.max(u);
            }
        }
    }
    let span = (umax - umin).max(1.0);
    let nb = n_slices;
    let mut bmin = vec![f32::INFINITY; nb];
    let mut bmax = vec![f32::NEG_INFINITY; nb];
    for y in 0..m.h {
        for x in 0..m.w {
            if m.fg[y * m.w + x] {
                let dx = x as f32 - p.cx;
                let dy = y as f32 - p.cy;
                let u = dx * p.ux + dy * p.uy;
                let t = dx * p.vx + dy * p.vy;
                let bi = (((u - umin) / span) * (nb as f32 - 1.0)).round() as usize;
                let bi = bi.min(nb - 1);
                bmin[bi] = bmin[bi].min(t);
                bmax[bi] = bmax[bi].max(t);
            }
        }
    }
    // Fill empty bins by neighbor interpolation; compute center & half.
    for i in 0..nb {
        if bmin[i].is_infinite() {
            // find nearest filled left/right
            let mut l = i as isize - 1;
            while l >= 0 && bmin[l as usize].is_infinite() {
                l -= 1;
            }
            let mut r = i + 1;
            while r < nb && bmin[r].is_infinite() {
                r += 1;
            }
            if l >= 0 && r < nb {
                let a = bmin[l as usize];
                let b = bmin[r];
                let c = bmax[l as usize];
                let d = bmax[r];
                bmin[i] = (a + b) * 0.5;
                bmax[i] = (c + d) * 0.5;
            } else if l >= 0 {
                bmin[i] = bmin[l as usize];
                bmax[i] = bmax[l as usize];
            } else if r < nb {
                bmin[i] = bmin[r];
                bmax[i] = bmax[r];
            } else {
                bmin[i] = 0.0;
                bmax[i] = 0.0;
            }
        }
    }
    let mut u = Vec::with_capacity(nb);
    let mut t = Vec::with_capacity(nb);
    let mut half = Vec::with_capacity(nb);
    let uc = (umin + umax) * 0.5;
    for i in 0..nb {
        let uu = umin + span * (i as f32 / (nb as f32 - 1.0));
        u.push(uu - uc); // center axial coordinate
        t.push((bmin[i] + bmax[i]) * 0.5);
        half.push(((bmax[i] - bmin[i]) * 0.5).max(0.0));
    }
    // Smooth centerline & width a touch (3-tap) to kill segmentation jitter.
    let smooth = |v: &mut Vec<f32>| {
        let src = v.clone();
        for i in 1..nb - 1 {
            v[i] = 0.25 * src[i - 1] + 0.5 * src[i] + 0.25 * src[i + 1];
        }
    };
    smooth(&mut t);
    smooth(&mut half);
    smooth(&mut half);
    Profile {
        u,
        t,
        half,
        umin: umin - uc,
        umax: umax - uc,
    }
}

// Extract a normalized cross-section ring from an END-ON image: for `k` angles,
// the radius (fraction of max) of the silhouette boundary. Falls back to a
// rounded, slightly-flattened banana cross-section if the image is unusable.
fn extract_cross_section(end: Option<&Mask>, k: usize, depth_ratio: f32) -> Vec<(f32, f32)> {
    // Returns k unit-ring offsets (a along profile-width dir, b along depth dir),
    // both in [-1,1], to be scaled by halfWidth at each slice.
    if let Some(m) = end {
        let p = pca(m);
        // radial profile around centroid in the end-on image plane.
        let mut rmax = vec![0f32; k];
        for y in 0..m.h {
            for x in 0..m.w {
                if m.fg[y * m.w + x] {
                    let dx = x as f32 - p.cx;
                    let dy = y as f32 - p.cy;
                    // express in (major, minor) so it is orientation-free
                    let a = dx * p.ux + dy * p.uy;
                    let b = dx * p.vx + dy * p.vy;
                    let ang = b.atan2(a); // [-pi,pi]
                    let r = (a * a + b * b).sqrt();
                    let bi = (((ang + std::f32::consts::PI) / (2.0 * std::f32::consts::PI))
                        * k as f32) as usize
                        % k;
                    if r > rmax[bi] {
                        rmax[bi] = r;
                    }
                }
            }
        }
        let peak = rmax.iter().cloned().fold(0f32, f32::max).max(1.0);
        // Sanity: an end-on banana silhouette should be a compact blob with a
        // reasonable fill. If it degenerated, fall through to the analytic form.
        let filled = rmax.iter().filter(|&&r| r > 0.0).count();
        if filled as f32 / k as f32 > 0.85 {
            let mut ring = Vec::with_capacity(k);
            for i in 0..k {
                let ang = -std::f32::consts::PI
                    + (i as f32 + 0.5) / k as f32 * 2.0 * std::f32::consts::PI;
                let r = (rmax[i] / peak).clamp(0.15, 1.0);
                // map: 'a' = profile-width direction (the silhouette's minor /
                // thickness), 'b' = depth. Use the end-on minor extent as depth.
                ring.push((r * ang.cos(), r * ang.sin()));
            }
            return ring;
        }
    }
    // Analytic fallback: a smooth rounded-flattened banana cross-section. No hard
    // keel/crease (a kink there makes a bright dashed highlight under Gouraud);
    // instead a gentle, C1-continuous asymmetry: a touch flatter on the back, a
    // touch rounder on the belly. a in [-1,1] (profile half-width), b = depth.
    let mut ring = Vec::with_capacity(k);
    for i in 0..k {
        let ang = (i as f32 + 0.5) / k as f32 * 2.0 * std::f32::consts::PI;
        let a = ang.cos();
        // smooth depth asymmetry via cos(ang) (no max/kink): belly slightly deeper.
        let asym = 1.0 + 0.12 * ang.sin(); // >1 belly, <1 back, smooth everywhere
        let b = ang.sin() * depth_ratio * asym;
        ring.push((a, b));
    }
    ring
}

fn main() {
    // --- arg parsing (tiny, dependency-light) ---
    let mut profile_path: Option<PathBuf> = None;
    let mut end_path: Option<PathBuf> = None;
    let mut out_path = PathBuf::from("/tmp/banana.ply");
    let mut thresh = 0.10f32;
    let mut n_slices = 96usize;
    let mut k_ring = 28usize;
    let mut depth_ratio = 0.85f32;
    let mut target_len = 2.0f32;
    let mut max_dim = 900u32;
    let mut use_end = true;

    let args: Vec<String> = std::env::args().collect();
    let mut i = 1;
    while i < args.len() {
        match args[i].as_str() {
            "--profile" => {
                i += 1;
                profile_path = Some(PathBuf::from(&args[i]));
            }
            "--end" => {
                i += 1;
                end_path = Some(PathBuf::from(&args[i]));
            }
            "--out" => {
                i += 1;
                out_path = PathBuf::from(&args[i]);
            }
            "--thresh" => {
                i += 1;
                thresh = args[i].parse().unwrap();
            }
            "--slices" => {
                i += 1;
                n_slices = args[i].parse().unwrap();
            }
            "--ring" => {
                i += 1;
                k_ring = args[i].parse().unwrap();
            }
            "--depth" => {
                i += 1;
                depth_ratio = args[i].parse().unwrap();
            }
            "--len" => {
                i += 1;
                target_len = args[i].parse().unwrap();
            }
            "--maxdim" => {
                i += 1;
                max_dim = args[i].parse().unwrap();
            }
            "--no-end" => {
                use_end = false;
            }
            other => panic!("unknown arg {}", other),
        }
        i += 1;
    }
    let profile_path = profile_path.expect("--profile <image> required");

    eprintln!("[sweep] loading profile {:?}", profile_path);
    let pm = load_mask(&profile_path, thresh, max_dim);
    let p = pca(&pm);
    let mut prof = extract_profile(&pm, &p, n_slices);
    // --- Truncate the long thin STEM stalk into a short stubby nub. ---
    // The photo silhouette includes the banana's stalk (a long thin protrusion
    // ~0.25 of max width). A real banana ends in a short blunt nub, so we find the
    // leading/trailing run of slices below a width threshold and keep only a few.
    {
        let hwmax = prof.half.iter().cloned().fold(0f32, f32::max).max(1e-3);
        let thin = 0.42 * hwmax;
        let keep = 4usize; // stem nub length (slices) to retain
                           // leading thin run
        let mut lead = 0usize;
        while lead < prof.half.len() && prof.half[lead] < thin {
            lead += 1;
        }
        // trailing thin run
        let mut trail = prof.half.len();
        while trail > 0 && prof.half[trail - 1] < thin {
            trail -= 1;
        }
        let drop_lead = lead.saturating_sub(keep);
        let drop_trail = if prof.half.len() - trail > keep {
            prof.half.len() - trail - keep
        } else {
            0
        };
        if drop_lead > 0 || drop_trail > 0 {
            let hi = prof.half.len() - drop_trail;
            prof.u = prof.u[drop_lead..hi].to_vec();
            prof.t = prof.t[drop_lead..hi].to_vec();
            prof.half = prof.half[drop_lead..hi].to_vec();
            // re-center axial coordinate
            let umin = *prof.u.first().unwrap();
            let umax = *prof.u.last().unwrap();
            let uc = (umin + umax) * 0.5;
            for v in prof.u.iter_mut() {
                *v -= uc;
            }
            prof.umin = umin - uc;
            prof.umax = umax - uc;
            eprintln!(
                "[sweep] stem trim: dropped {} lead + {} trail thin slices -> {} slices",
                drop_lead,
                drop_trail,
                prof.u.len()
            );
        }
    }
    let aspect =
        (prof.umax - prof.umin) / (prof.half.iter().cloned().fold(0f32, f32::max).max(1.0) * 2.0);
    eprintln!("[sweep] profile aspect (length/max-width) = {:.2}", aspect);
    if std::env::var("SWEEP_DEBUG").is_ok() {
        let hwmax = prof.half.iter().cloned().fold(0f32, f32::max).max(1e-3);
        let frac: Vec<String> = prof
            .half
            .iter()
            .map(|h| format!("{:.2}", h / hwmax))
            .collect();
        eprintln!("[sweep] halfwidth/max per slice: {}", frac.join(" "));
    }

    let end_mask = if use_end {
        end_path.as_ref().map(|ep| {
            eprintln!("[sweep] loading end-on {:?}", ep);
            load_mask(ep, thresh, max_dim)
        })
    } else {
        None
    };
    let ring = extract_cross_section(end_mask.as_ref(), k_ring, depth_ratio);
    let from_image = end_mask.is_some() && {
        // re-derive whether image path was taken (extract logged nothing; recompute cheaply)
        true
    };
    eprintln!(
        "[sweep] cross-section: {} sampled angles ({})",
        k_ring,
        if from_image && depth_ratio > 0.0 {
            "end-on or analytic"
        } else {
            "analytic"
        }
    );

    // --- Build the swept surface in image-pixel units, then normalize. ---
    // Long axis = X (from axial u), curve in XY (centerline t -> Y),
    // cross-section spans Y (profile width, via ring.0) and Z (depth, via ring.1).
    //
    // We place each slice's local frame: axial dir = +X, the profile-width
    // direction = +Y, depth = +Z. The centerline curve lives in XY (it is what
    // the profile image SHOWS). ring.0 multiplies halfWidth along Y, ring.1 along
    // Z (depth = halfWidth * depth_ratio already baked into analytic ring; for the
    // image ring we scale Z by depth_ratio here).
    let ns = prof.u.len();
    let kr = ring.len();

    // --- Stem nub: keep the ends blunt, not needles. ---
    // A real banana ends in a STUBBY nub, not a thin stalk. The photo silhouette
    // includes the thin stem, so the raw half-width tapers to ~0 (a needle). We
    // (1) enforce a minimum half-width floor that ramps up over the end region so
    // the very tip is a rounded nub, and (2) the cap tip is pulled in close to the
    // end ring (short cap) instead of out at a sharp point.
    let hw_max = prof.half.iter().cloned().fold(0f32, f32::max).max(1e-3);
    let nub = hw_max * 0.20; // half-width at the very ends (stubby)
    let mut half_adj = prof.half.clone();
    let edge_n = (((ns as f32) * 0.14).round() as usize).max(3); // ramp length
    for i in 0..ns {
        let d_end = i.min(ns - 1 - i); // slices from nearest end
        if d_end <= edge_n {
            // smoothstep floor: nub at the very end -> 0 contribution at ramp inner
            let t = d_end as f32 / edge_n as f32; // 0..1
            let s = t * t * (3.0 - 2.0 * t); // smoothstep
            let floor = nub * (1.0 - s);
            if half_adj[i] < floor {
                half_adj[i] = floor;
            }
        }
    }

    // Vertices: ns rings of kr verts, plus we will cap the two ends with the
    // first/last ring collapsed to a (short) tip point.
    let mut verts: Vec<[f32; 3]> = Vec::new();
    let mut cols: Vec<[u8; 3]> = Vec::new();

    // --- Robust, specular-suppressed color sampling. ---
    // saturation/brightness of an RGB triple in [0,1].
    let sat_val = |r: u8, g: u8, b: u8| -> (f32, f32) {
        let (rf, gf, bf) = (r as f32 / 255.0, g as f32 / 255.0, b as f32 / 255.0);
        let mx = rf.max(gf).max(bf);
        let mn = rf.min(gf).min(bf);
        let s = if mx <= 1e-5 { 0.0 } else { (mx - mn) / mx };
        (s, mx)
    };
    // Per-slice MEDIAN skin color from interior samples (rim + specular excluded).
    // We sample across the silhouette band (ra in [-0.6,0.6], interior) and a few
    // pixels along the axis, collect non-specular non-rim pixels, take the median.
    let pixel_at = |u_world: f32, t_world: f32| -> Option<[u8; 3]> {
        let px = p.cx + u_world * p.ux + t_world * p.vx;
        let py = p.cy + u_world * p.uy + t_world * p.vy;
        let xi = px.round();
        let yi = py.round();
        if xi < 0.0 || yi < 0.0 || xi >= pm.w as f32 || yi >= pm.h as f32 {
            return None;
        }
        let (xi, yi) = (xi as usize, yi as usize);
        if !pm.fg[yi * pm.w + xi] {
            return None;
        }
        let idx = (yi * pm.w + xi) * 3;
        Some([pm.rgb[idx], pm.rgb[idx + 1], pm.rgb[idx + 2]])
    };
    // Use the 62nd percentile per channel — biases toward the brighter, riper
    // yellow (the median tends to land on the darker speckle band -> olive skin).
    let median3 = |v: &mut Vec<[u8; 3]>| -> Option<[u8; 3]> {
        if v.is_empty() {
            return None;
        }
        let mut comp = |c: usize| -> u8 {
            v.sort_by_key(|p| p[c]);
            let k = ((v.len() as f32 - 1.0) * 0.62).round() as usize;
            v[k.min(v.len() - 1)][c]
        };
        Some([comp(0), comp(1), comp(2)])
    };
    // A pixel is SPECULAR if it is bright AND low-saturation (the white sheen),
    // i.e. it has lost the banana's yellow chroma. Brown speckles (dark, still
    // somewhat saturated) and ripe yellow (saturated, bright) are kept.
    let is_specular = |r: u8, g: u8, b: u8| -> bool {
        let (s, val) = sat_val(r, g, b);
        // bright + chroma-washed (the white sheen and its halo) -> specular.
        (val > 0.74 && s < 0.46) || (val > 0.90)
    };
    let mut slice_median: Vec<[u8; 3]> = Vec::with_capacity(ns);
    for s in 0..ns {
        let u = prof.u[s];
        let hw = prof.half[s].max(1e-3);
        let mut samples: Vec<[u8; 3]> = Vec::new();
        for du in [-1.0f32, 0.0, 1.0] {
            for fr in [-0.55f32, -0.3, -0.1, 0.1, 0.3, 0.55] {
                if let Some(c) = pixel_at(u + du * (hw * 0.12), prof.t[s] + fr * hw) {
                    if !is_specular(c[0], c[1], c[2]) {
                        samples.push(c);
                    }
                }
            }
        }
        // fall back: include any interior pixel if everything was specular
        if samples.is_empty() {
            for fr in [-0.55f32, 0.0, 0.55] {
                if let Some(c) = pixel_at(u, prof.t[s] + fr * hw) {
                    samples.push(c);
                }
            }
        }
        slice_median.push(median3(&mut samples).unwrap_or([210, 180, 40]));
    }
    // Lift the median toward a brighter ripe yellow: the photo's shadowed
    // back/underside reads olive, but the back of a real banana is still yellow.
    // Gentle gamma-style brighten of R,G (keep B low) -> golden, not olive.
    for m in slice_median.iter_mut() {
        let lift = |v: u8, amt: f32| -> u8 {
            let f = v as f32 / 255.0;
            ((f.powf(0.80) * (1.0 + amt)).min(1.0) * 255.0).round() as u8
        };
        m[0] = lift(m[0], 0.06); // R
        m[1] = lift(m[1], 0.04); // G
                                 // B left as-is to keep the yellow chroma (don't wash to grey)
    }
    // Smooth the per-slice median along the axis (kills any residual jumps / seam).
    // Several passes -> an even ripe-yellow skin tone with no banding in the median.
    for _ in 0..4 {
        let src = slice_median.clone();
        for i in 1..ns - 1 {
            for c in 0..3 {
                slice_median[i][c] =
                    ((src[i - 1][c] as u16 + 2 * src[i][c] as u16 + src[i + 1][c] as u16) / 4)
                        as u8;
            }
        }
    }

    // Final per-vertex color: sample the real silhouette band for surface detail
    // (speckles), but if the sample is specular OR off-band (depth/back vert),
    // fall back to the slice median. Blend toward the median to keep skin even.
    let surface_color = |s: usize, ra: f32, on_front: f32| -> [u8; 3] {
        let u = prof.u[s];
        let hw = prof.half[s].max(1e-3);
        let med = slice_median[s];
        // sample only meaningful when this vert faces the camera (front band);
        // back/side verts use the median so the seam is invisible.
        let raw = pixel_at(u, prof.t[s] + ra * hw);
        let base = match raw {
            Some(c) if !is_specular(c[0], c[1], c[2]) => c,
            _ => med,
        };
        // blend detail toward median by how front-facing this vert is.
        let mix = |a: u8, b: u8| -> u8 {
            (a as f32 * on_front + b as f32 * (1.0 - on_front)).round() as u8
        };
        [
            mix(base[0], med[0]),
            mix(base[1], med[1]),
            mix(base[2], med[2]),
        ]
    };

    for s in 0..ns {
        let u = prof.u[s];
        let hw = half_adj[s];
        let cy = prof.t[s]; // centerline offset (Y in world)
        for r in 0..kr {
            let (ra, rb) = ring[r];
            // ra along profile-width (Y), rb along depth (Z)
            let y = cy + ra * hw;
            let z = rb * hw;
            verts.push([u, y, z]);
            // The profile photo was shot from +Z, so only the FRONT hemisphere
            // (rb > 0) actually saw that texture. Front verts keep the sampled
            // speckle detail; the crest (rb~0) and back (rb<0) fade to the smooth
            // slice median -> no bright lit-edge stripe wrapping onto the crest.
            let on_front = rb.max(0.0).clamp(0.0, 1.0).powf(0.7) * 0.9;
            cols.push(surface_color(s, ra, on_front));
        }
    }
    // Two tip points (caps) — short nubs, colored by the slice median.
    let tip0_idx = verts.len();
    verts.push([prof.u[0], prof.t[0], 0.0]);
    cols.push(slice_median[0]);
    let tip1_idx = verts.len();
    verts.push([prof.u[ns - 1], prof.t[ns - 1], 0.0]);
    cols.push(slice_median[ns - 1]);

    // --- Faces ---
    let mut faces: Vec<[usize; 3]> = Vec::new();
    for s in 0..ns - 1 {
        for r in 0..kr {
            let r2 = (r + 1) % kr;
            let a = s * kr + r;
            let b = s * kr + r2;
            let c = (s + 1) * kr + r;
            let d = (s + 1) * kr + r2;
            faces.push([a, c, b]);
            faces.push([b, c, d]);
        }
    }
    // Cap start (slice 0) to tip0, cap end (slice ns-1) to tip1.
    for r in 0..kr {
        let r2 = (r + 1) % kr;
        faces.push([tip0_idx, r2, r]);
        let base = (ns - 1) * kr;
        faces.push([tip1_idx, base + r, base + r2]);
    }

    // --- Taubin λ/μ smoothing (volume-preserving) to kill slice banding. ---
    // Build a vertex adjacency for the ring grid (ns x kr) so smoothing averages
    // ACROSS slices and AROUND rings. Cap tips are pinned (excluded as movers but
    // included as neighbors of the end rings). A few λ(+)/μ(-) passes flatten the
    // step banding without shrinking the banana.
    {
        let nv = verts.len();
        // adjacency as flat lists
        let mut adj: Vec<Vec<usize>> = vec![Vec::new(); nv];
        let connect = |a: usize, b: usize, adj: &mut Vec<Vec<usize>>| {
            adj[a].push(b);
            adj[b].push(a);
        };
        for s in 0..ns {
            for r in 0..kr {
                let i = s * kr + r;
                let r2 = (r + 1) % kr;
                connect(i, s * kr + r2, &mut adj); // around ring
                if s + 1 < ns {
                    connect(i, (s + 1) * kr + r, &mut adj); // across slices
                }
            }
        }
        // tip caps connect to their end rings
        for r in 0..kr {
            connect(tip0_idx, r, &mut adj);
            connect(tip1_idx, (ns - 1) * kr + r, &mut adj);
        }
        // pin the two extreme end rings + tips so the nub keeps its shape
        let mut pinned = vec![false; nv];
        pinned[tip0_idx] = true;
        pinned[tip1_idx] = true;
        for r in 0..kr {
            pinned[r] = true;
            pinned[(ns - 1) * kr + r] = true;
        }
        let lambda = 0.5f32;
        let mu = -0.53f32;
        let pass =
            |verts: &mut Vec<[f32; 3]>, factor: f32, adj: &Vec<Vec<usize>>, pinned: &Vec<bool>| {
                let src = verts.clone();
                for i in 0..src.len() {
                    if pinned[i] || adj[i].is_empty() {
                        continue;
                    }
                    let mut avg = [0f32; 3];
                    for &j in &adj[i] {
                        for d in 0..3 {
                            avg[d] += src[j][d];
                        }
                    }
                    let n = adj[i].len() as f32;
                    for d in 0..3 {
                        let lap = avg[d] / n - src[i][d];
                        verts[i][d] = src[i][d] + factor * lap;
                    }
                }
            };
        for _ in 0..6 {
            pass(&mut verts, lambda, &adj, &pinned);
            pass(&mut verts, mu, &adj, &pinned);
        }
    }

    // --- Normalize: center at origin, scale so X-length == target_len. ---
    let mut lo = [f32::INFINITY; 3];
    let mut hi = [f32::NEG_INFINITY; 3];
    for v in &verts {
        for d in 0..3 {
            lo[d] = lo[d].min(v[d]);
            hi[d] = hi[d].max(v[d]);
        }
    }
    let ctr = [
        (lo[0] + hi[0]) * 0.5,
        (lo[1] + hi[1]) * 0.5,
        (lo[2] + hi[2]) * 0.5,
    ];
    let xlen = (hi[0] - lo[0]).max(1e-6);
    let scale = target_len / xlen;
    for v in verts.iter_mut() {
        for d in 0..3 {
            v[d] = (v[d] - ctr[d]) * scale;
        }
    }

    // --- Per-vertex normals (area-weighted face normals). ---
    let mut norms = vec![[0f32; 3]; verts.len()];
    for f in &faces {
        let a = verts[f[0]];
        let b = verts[f[1]];
        let c = verts[f[2]];
        let e1 = [b[0] - a[0], b[1] - a[1], b[2] - a[2]];
        let e2 = [c[0] - a[0], c[1] - a[1], c[2] - a[2]];
        let n = [
            e1[1] * e2[2] - e1[2] * e2[1],
            e1[2] * e2[0] - e1[0] * e2[2],
            e1[0] * e2[1] - e1[1] * e2[0],
        ];
        for &vi in f {
            for d in 0..3 {
                norms[vi][d] += n[d];
            }
        }
    }
    for n in norms.iter_mut() {
        let l = (n[0] * n[0] + n[1] * n[1] + n[2] * n[2]).sqrt().max(1e-9);
        n[0] /= l;
        n[1] /= l;
        n[2] /= l;
    }

    // --- Smooth the vertex normals across the ring grid. ---
    // The Gouraud launcher shades from these baked normals; per-slice normal
    // jitter shows up as a dashed crest highlight in the top view. Averaging each
    // normal with its ring + slice neighbors (several passes) turns the crest into
    // a smooth gradient with no dashes, without moving any geometry.
    {
        let mut adj: Vec<Vec<usize>> = vec![Vec::new(); verts.len()];
        let connect = |a: usize, b: usize, adj: &mut Vec<Vec<usize>>| {
            adj[a].push(b);
            adj[b].push(a);
        };
        for s in 0..ns {
            for r in 0..kr {
                let i = s * kr + r;
                connect(i, s * kr + (r + 1) % kr, &mut adj);
                if s + 1 < ns {
                    connect(i, (s + 1) * kr + r, &mut adj);
                }
            }
        }
        for r in 0..kr {
            connect(tip0_idx, r, &mut adj);
            connect(tip1_idx, (ns - 1) * kr + r, &mut adj);
        }
        for _ in 0..8 {
            let src = norms.clone();
            for i in 0..norms.len() {
                if adj[i].is_empty() {
                    continue;
                }
                let mut acc = [src[i][0], src[i][1], src[i][2]];
                for &j in &adj[i] {
                    for d in 0..3 {
                        acc[d] += src[j][d];
                    }
                }
                let l = (acc[0] * acc[0] + acc[1] * acc[1] + acc[2] * acc[2])
                    .sqrt()
                    .max(1e-9);
                norms[i] = [acc[0] / l, acc[1] / l, acc[2] / l];
            }
        }
    }

    // --- Write faced PLY ---
    let f = File::create(&out_path).unwrap();
    let mut w = BufWriter::new(f);
    writeln!(w, "ply").unwrap();
    writeln!(w, "format ascii 1.0").unwrap();
    writeln!(w, "comment monster-sweep-recon generalized-cylinder banana").unwrap();
    writeln!(w, "element vertex {}", verts.len()).unwrap();
    writeln!(w, "property float x").unwrap();
    writeln!(w, "property float y").unwrap();
    writeln!(w, "property float z").unwrap();
    writeln!(w, "property float nx").unwrap();
    writeln!(w, "property float ny").unwrap();
    writeln!(w, "property float nz").unwrap();
    writeln!(w, "property uchar red").unwrap();
    writeln!(w, "property uchar green").unwrap();
    writeln!(w, "property uchar blue").unwrap();
    writeln!(w, "element face {}", faces.len()).unwrap();
    writeln!(w, "property list uchar int vertex_indices").unwrap();
    writeln!(w, "end_header").unwrap();
    for (i, v) in verts.iter().enumerate() {
        let n = norms[i];
        let c = cols[i];
        writeln!(
            w,
            "{:.5} {:.5} {:.5} {:.4} {:.4} {:.4} {} {} {}",
            v[0], v[1], v[2], n[0], n[1], n[2], c[0], c[1], c[2]
        )
        .unwrap();
    }
    for f in &faces {
        writeln!(w, "3 {} {} {}", f[0], f[1], f[2]).unwrap();
    }
    w.flush().unwrap();

    let _ = Rgb([0u8, 0, 0]); // silence unused import in some configs
    eprintln!(
        "[sweep] wrote {} verts / {} faces -> {:?}",
        verts.len(),
        faces.len(),
        out_path
    );
    eprintln!(
        "[sweep] dims after normalize: X={:.3} Y={:.3} Z={:.3}",
        (hi[0] - lo[0]) * scale,
        (hi[1] - lo[1]) * scale,
        (hi[2] - lo[2]) * scale
    );
}
